parameters.functionCode:
// Split into one item per iteration + build the resume URL
return $input.first().json.map(row => ({
  json: {
    email: row.email,
    full_name: row.full_name,
    first_name: (row.full_name || '').split(' ')[0] || 'there',
    order_id: row.id,
    amount_usd: row.amount_usd,
    resume_url: `https://sericia.com/cart?recover=${row.id}`,
    item_names: (row.items || []).map(i => i.product_snapshot?.name || 'your selection').join(', ')
  }
}));

parameters.jsonBody:
={
  "from": "Sericia <contact@sericia.com>",
  "to": $json.email,
  "subject": "Your Sericia drop is still reserved — $" + $json.amount_usd,
  "html": `<div style=\"font-family:Georgia,serif;max-width:560px;margin:0 auto;color:#2b221c\"><h1 style=\"font-weight:normal\">A quick nudge, ${$json.first_name}.</h1><p>Your items (${$json.item_names}) are still on hold — but craft-food drops are small-batch and other buyers are browsing the same SKUs.</p><p style=\"margin-top:28px\"><a href=\"${$json.resume_url}\" style=\"background:#b8860b;color:white;padding:12px 28px;text-decoration:none;border-radius:4px\">Continue to payment →</a></p><p style=\"color:#6b5e4f;font-size:13px;margin-top:32px\">Questions? Reply or write <a href=\"mailto:contact@sericia.com\">contact@sericia.com</a>.</p></div>`
}
